sql:
SELECT COUNT(creator_id) AS active_creators_count
FROM content_creators
WHERE status = 'active';

SELECT COUNT(*) AS total_active_creators
FROM content_creators cc
WHERE cc.status = 'active';

external_knowledge:
- "Shining star" metaphorically refers to the content creator with the highest viewership;
- "Year just passed" refers to the year before the current year (i.e., the previous year);
- "Attracting the largest crowd on average" means having the highest average number of viewers per stream.

sql:
SELECT SUM(viewers_month) AS total_viewers
FROM viewership_metrics
WHERE month = 'January' AND year = 2023;
